> Clicking a plain sibling <label> (even with for/id set correctly) is unable to toggle span role="checkbox"

It seems to work with a minimal repro:

```jsx
export default function Checkbox() {
  const ref = React.useRef<HTMLSpanElement>(null);
  const [checked, setChecked] = React.useState(false);
  return (
    <div>
      <label htmlFor="checkbox">Checkbox</label>
      <span
        ref={ref}
        role="checkbox"
        aria-checked={checked}
        style={{
          display: 'inline-block',
          width: 20,
          height: 20,
          background: checked ? 'blue' : 'gray',
        }}
        onClick={() => setChecked(!checked)}
        tabIndex={0}
      />
      <input
        id="checkbox"
        onFocus={() => {
          ref.current?.focus();
        }}
        onClick={() => {
          ref.current?.click();
        }}
        tabIndex={-1}
        aria-hidden
      />
    </div>
  );
}
```
